{
  "hooks": {
    "Stop": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "cd \"/Users/martinminghetti/Documents/Obsidian Vault\" && CHANGES=$(git status --porcelain | wc -l | tr -d ' ') && if [ \"$CHANGES\" -gt 0 ]; then git add . && git commit -m \"Auto-sync vault ($(date +%Y-%m-%d))\" 2>/dev/null && printf '{\"systemMessage\":\"Vault auto-committed (%s files)\"}' \"$CHANGES\"; fi",
            "timeout": 30,
            "statusMessage": "Auto-committing vault changes..."
          }
        ]
      }
    ],
    "SessionStart": [
      {
        "hooks": [
          {
            "type": "command",
            "command": "/Users/martinminghetti/Documents/Obsidian\\ Vault/.claude/vault-health-check.sh",
            "timeout": 10,
            "statusMessage": "Checking vault health..."
          }
        ]
      }
    ],
    "PostToolUse": [
      {
        "matcher": "Write|Edit",
        "hooks": [
          {
            "type": "command",
            "command": "jq -r '.tool_input.file_path // .tool_response.filePath // empty' | { read -r f; if echo \"$f\" | grep -qE 'daily/.*tldr'; then printf '{\"hookSpecificOutput\":{\"hookEventName\":\"PostToolUse\",\"additionalContext\":\"TLDR guardado. Recordar: si cambio el estado de un proyecto, actualizar tambien su NOW.md y memory/active.md.\"}}'; fi; } 2>/dev/null || true",
            "timeout": 5,
            "statusMessage": "Checking vault sync..."
          }
        ]
      }
    ]
  }
}
